def gen(rng, size):
    import string
    alpha = string.ascii_letters + string.digits
    chars = []
    for _ in range(max(1, size)):
        if rng.random() < 0.2:
            chars.append('-')
        else:
            chars.append(rng.choice(alpha))
    k = rng.randint(1, 20)
    return [''.join(chars), k]

