class Solution:
    def licenseKeyFormatting(self, s, k):
        clean = ''.join(ch for ch in s if ch != '-').upper()
        if not clean:
            return ''
        rem = len(clean) % k
        groups = []
        i = 0
        if rem:
            groups.append(clean[:rem])
            i = rem
        while i < len(clean):
            groups.append(clean[i:i + k])
            i += k
        return '-'.join(groups)

