class Solution:
    def licenseKeyFormatting(self, s, k):
        clean = [ch.upper() for ch in s if ch != '-']
        out = []
        count = 0
        for ch in reversed(clean):
            if count == k:
                out.append('-')
                count = 0
            out.append(ch)
            count += 1
        return ''.join(reversed(out))

