var licenseKeyFormatting = function(s, k) {
    const out = [];
    let count = 0;
    for (let i = s.length - 1; i >= 0; i--) {
        const ch = s[i];
        if (ch === '-') continue;
        if (count === k) {
            out.push('-');
            count = 0;
        }
        out.push(ch.toUpperCase());
        count++;
    }
    return out.reverse().join('');
};
